#include <bits/stdc++.h>
using namespace std;
int s,n,m,a[102][102];
long long dp[50004];
int main(){
    scanf("%d%d%d",&s,&n,&m);
    for(int i=1;i<=s;i++)
        for(int j=1;j<=n;j++)
            scanf("%d",&a[j][i]);
    for(int i=1;i<=n;i++)
        sort(&a[i][1],&a[i][s]+1);
    for(int i=1;i<=n;i++)
        for(int k=m;k>=0;k--)
            for(int j=1;j<=s;j++){
                if(k>a[i][j]*2)
                    dp[k]=max(dp[k],dp[k-a[i][j]*2-1]+j*i);
            }
    printf("%lld",dp[m]);
    return 0;
}
